SET pClassification=#{pClassification}
    , pName=#{pName}
    , pPrice=#{pPrice}
WHERE pno=#{pno}

UPDATE productOp
SET pOpNo=#{pOpNo}
    , pSize=#{pSize}
    , pColor=#{pColor}
    , pStock=#{pStock}
